var $jscomp = $jscomp || {};
$jscomp.scope = {};
$jscomp.arrayIteratorImpl = function(a) {
    var b = 0;
    return function() {
        return b < a.length ? {
            done: !1,
            value: a[b++]
        } : {
            done: !0
        }
    }
}
;
$jscomp.arrayIterator = function(a) {
    return {
        next: $jscomp.arrayIteratorImpl(a)
    }
}
;
$jscomp.makeIterator = function(a) {
    var b = "undefined" != typeof Symbol && Symbol.iterator && a[Symbol.iterator];
    return b ? b.call(a) : $jscomp.arrayIterator(a)
}
;
var k = "الأحد الإثنين الثلاثاء الأربعاء الخميس الجمعة السبت".split(" ");

function fitText(a, b) {
    if(a && a.innerText) {
        a.style.fontSize = Math.ceil(10 * a.clientWidth * (b || 1) / a.innerText.length) + "px";
    }
    return a;
}

function l(a) {
    if(!a) return;
    var b, g = null != (b = a.getAttribute("hot-img-path")) ? b : "1.jpg";
    a.style.textAlign = "center";
    var c = new Image;
    c.src = "adv_img/" + g;
    c.classList.add("adv-img");
    c.complete ? a.innerHTML = c.outerHTML : (c.onload = function() {
        a.innerHTML = c.outerHTML
    },
    c.onerror = function() {
        var logo = document.querySelector(".logo");
        if(logo) logo.style.paddingTop = "50px";
        var section = document.querySelector(".section");
        if(section && section.hasAttribute("enable-hot-marquee")) {
            section.style.display = "block";
        }
    }
    )
}

function p(a) {
    if(!a) return;
    a.innerHTML = q();
    setInterval(function() {
        a.innerHTML = q()
    }, 1000);
}

function q() {
    var a = new Date;
    var b = ("0" + a.getSeconds()).slice(-2);
    var g = ("0" + a.getMinutes()).slice(-2);
    var hours = ("0" + a.getHours()).slice(-2);
    var period = "صباحاً";
    var hourNum = parseInt(hours);
    if(hourNum >= 12) {
        var displayHour = hourNum > 12 ? hourNum - 12 : hourNum;
        hours = ("0" + displayHour).slice(-2);
        period = "مساءً";
    }
    return "الساعة الان " + hours + ":" + g + ":" + b + " " + period;
}

function startFitText() {
    var elements = document.querySelectorAll("[data-fit-text]");
    if(elements) {
        for(var i = 0; i < elements.length; i++) {
            fitText(elements[i], 0.215);
        }
    }
}

document.addEventListener("DOMContentLoaded", function() {
    var dateElement = document.querySelector("[hot-date]");
    if(dateElement !== null) {
        var now = new Date();
        var monthNames = "يناير فبراير مارس ابريل مايو يونيو يوليو اغسطس سبتمبر اكتوبر نوفمبر ديسمبر".split(" ");
        dateElement.innerHTML = k[now.getDay()] + " " + now.getDate() + " " + monthNames[now.getMonth()] + " " + now.getFullYear();
    }
    
    var timeElement = document.querySelector("[hot-time]");
    if(timeElement !== null) {
        p(timeElement);
    }
    
    var advElement = document.querySelector("div[hot-adv-img]");
    if(advElement !== null) {
        l(advElement);
    }
    
    var hijriElement = document.querySelector("[hot-hijri-date]");
    if(hijriElement !== null) {
        var adjustDays = hijriElement.getAttribute("hot-adjust-days");
        var withDay = hijriElement.getAttribute("hot-with-day") !== null;
        var currentDate = new Date();
        if(adjustDays) {
            currentDate.setDate(currentDate.getDate() + parseInt(adjustDays));
        }
        var day = currentDate.getDate();
        var month = currentDate.getMonth() + 1;
        var year = currentDate.getFullYear();
        
        // Simplified Hijri date calculation
        var hijriYear = Math.floor((year - 622) * 0.97);
        var hijriMonth = month;
        var hijriDay = day;
        
        var hijriMonths = "محرم;صفر;ربيع الأول;ربيع الثاني;جمادى الأولى;جمادى الثانية;رجب;شعبان;رمضان;شوال;ذو القعدة;ذو الحجة".split(";");
        var hijriDate = hijriDay + " " + hijriMonths[hijriMonth - 1] + " " + hijriYear;
        
        if(withDay) {
            hijriDate = k[currentDate.getDay()] + ", " + hijriDate;
        }
        hijriElement.innerText = hijriDate;
    }
}, false);
